sql:
SELECT AVG(average_co) AS average_co_index
FROM historical_data
WHERE station_id = 1;

SELECT ms.station_name, hd.average_pm2_5
FROM monitoring_stations ms
LEFT JOIN historical_data hd ON ms.station_id = hd.station_id;

SELECT DISTINCT ms.station_name
FROM monitoring_stations ms
INNER JOIN alerts a ON ms.station_id = a.station_id;

SELECT hd.average_co, p.description
FROM historical_data hd
JOIN pollutants p ON hd.average_co = p.threshold;

SELECT recorded_date
FROM historical_data
ORDER BY recorded_date DESC;
